import{_ as a,o,c as t,ag as r}from"./chunks/framework.Culc7SYV.js";const f=JSON.parse('{"title":"Guide for Free Usage","description":"","frontmatter":{},"headers":[],"relativePath":"Guide-for-Free-Usage.md","filePath":"Guide-for-Free-Usage.md","lastUpdated":1773806339000}'),i={name:"Guide-for-Free-Usage.md"};function s(n,e,l,d,c,u){return o(),t("div",null,[...e[0]||(e[0]=[r('<h1 id="guide-for-free-usage" tabindex="-1">Guide for Free Usage <a class="header-anchor" href="#guide-for-free-usage" aria-label="Permalink to &quot;Guide for Free Usage&quot;">​</a></h1><p>Last modified: 10/03/2026</p><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Companion is bring-your-own-key. That means there is no LearnKit subscription requirement for Companion features.</p><p>You can run Companion with free-tier models if your provider account has free usage available.</p><h2 id="recommended-free-setup" tabindex="-1">Recommended free setup <a class="header-anchor" href="#recommended-free-setup" aria-label="Permalink to &quot;Recommended free setup&quot;">​</a></h2><ol><li>Open <strong>Settings → Companion</strong>.</li><li>Turn on <strong>Enable Companion</strong>.</li><li>Set <strong>AI provider</strong> to <strong>OpenRouter</strong>.</li><li>In OpenRouter, create an API key and paste it into <strong>API key</strong>.</li><li>Choose a free-capable model.</li></ol><p>If one model is unavailable or rate-limited, switch to another free-capable model.</p><h2 id="cost-control-checklist" tabindex="-1">Cost-control checklist <a class="header-anchor" href="#cost-control-checklist" aria-label="Permalink to &quot;Cost-control checklist&quot;">​</a></h2><p>Use these settings to reduce token usage and avoid accidental spend:</p><ul><li>Keep <strong>Approximate number of cards</strong> low while testing (for example, 3-5).</li><li>Turn off <strong>Include images from note in messages</strong> unless you need vision.</li><li>Keep prompts short and specific to reduce output size.</li><li>Disable card types you do not currently need in <strong>What flashcard types to generate</strong>.</li></ul><h2 id="free-usage-caveats" tabindex="-1">Free usage caveats <a class="header-anchor" href="#free-usage-caveats" aria-label="Permalink to &quot;Free usage caveats&quot;">​</a></h2><ul><li>Free model availability can change at any time by provider.</li><li>Response quality and speed can vary between free models.</li><li>Some free models do not support image understanding.</li><li>If a model fails, try another model first before troubleshooting other settings.</li></ul><h2 id="security-notes" tabindex="-1">Security notes <a class="header-anchor" href="#security-notes" aria-label="Permalink to &quot;Security notes&quot;">​</a></h2><ul><li>API keys are stored locally in your vault plugin data.</li><li>Do not commit plugin data files containing keys to public repositories.</li></ul><p>For privacy and safety details, see <a href="./AI-Usage-Policy">AI Usage Policy</a>.</p>',16)])])}const h=a(i,[["render",s]]);export{f as __pageData,h as default};
